import { gunzipSync } from "node:zlib"

// Generated from live https://amblast.nl WordPress/Elementor HTML captures.
// Capture time: 2026-06-27T20:40:42.480Z
const COMPRESSED_HTML = new Map([
  ["/", ""],
  ["/over-ons", ""],
  ["/diensten", ""],
  ["/portfolio-1", ""],
  ["/contact-pagina", ""],
  ["404", ""],
])

const decodedHtml = new Map()

export function getCapturedAmblastHtml(pathname) {
  const compressed = COMPRESSED_HTML.get(pathname)
  if (!compressed) return null
  const cached = decodedHtml.get(pathname)
  if (cached) return cached
  const html = gunzipSync(Buffer.from(compressed, "base64")).toString("utf8")
  decodedHtml.set(pathname, html)
  return html
}

export const capturedAmblastPaths = [...COMPRESSED_HTML.keys()]

